class MigrationRunner
{
    void ApplyMigrations(AppDbContext db)
    {
        // EF Core 9 breaking change: Migrate() now manages its own transactions
        // internally and throws if called inside a user-managed transaction.
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            db.Database.Migrate();
        });
    }
}

