using Microsoft.EntityFrameworkCore;

// -----------------------------------------------------------------------
// Cosmos DB – EF Core 9 breaking changes & required fixes
// Apply these patterns to your separate Cosmos DB project.
// -----------------------------------------------------------------------

class CosmosContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // BREAKING CHANGE 1 – Discriminator property renamed
        //
        // EF Core 9 changed the default Cosmos discriminator property
        // from "Discriminator" to "$type".  Existing documents already
        // store "Discriminator", so we must pin the old name to avoid
        // a mismatch that silently returns zero results.
        modelBuilder.Entity<Product>()
            .ToContainer("Products")
            .HasDiscriminator<string>("Discriminator");
    }
}

class ProductService
{
    // BREAKING CHANGE 2 – Synchronous Cosmos queries removed
    //
    // EF Core 9 removed synchronous query support for Cosmos DB.
    // All queries must use async methods; sync calls now throw
    // InvalidOperationException.

    // BEFORE (EF Core 8 – sync, no longer compiles / throws at runtime):
    //
    //   List<Product> GetExpensive(CosmosContext db)
    //   {
    //       return db.Products.Where(p => p.Price > 100).ToList();
    //   }

    // AFTER (EF Core 9 – async):
    async Task<List<Product>> GetExpensiveAsync(CosmosContext db)
    {
        return await db.Products
            .Where(p => p.Price > 100)
            .ToListAsync();
    }
}

class Product
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
    public decimal Price { get; set; }
}

